starter.javascript:
let height = 50;
let age = 15;
// OUTER: is height at least 48?
//   INNER: is age at least 12? -> "Enjoy the ride"
//   otherwise -> "Ride with an adult"
// else (too short) -> "Too short to ride"

reference.pseudocode:
height ← 50
age ← 15
IF(height ≥ 48)
{
  IF(age ≥ 12)
  {
    DISPLAY("Enjoy the ride")
  }
  ELSE
  {
    DISPLAY("Ride with an adult")
  }
}
ELSE
{
  DISPLAY("Too short to ride")
}

reference.python:
height = 50
age = 15
if height >= 48:
    if age >= 12:
        print("Enjoy the ride")
    else:
        print("Ride with an adult")
else:
    print("Too short to ride")

reference.javascript:
let height = 50;
let age = 15;
if (height >= 48) {
  if (age >= 12) {
    console.log("Enjoy the ride");
  } else {
    console.log("Ride with an adult");
  }
} else {
  console.log("Too short to ride");
}

