starter.javascript:
let height = 52;
let age = 14;
// OUTER: height >= 48 ?
//   MIDDLE: age >= 12 ?
//     INNER: age >= 16 ? -> "Enjoy the ride - front row unlocked"
//            else        -> "Enjoy the ride - back rows only"
//   else (age < 12) -> "Ride with an adult"
// else (too short)  -> "Too short to ride"

reference.pseudocode:
height ← 52
age ← 14
IF(height ≥ 48)
{
  IF(age ≥ 12)
  {
    IF(age ≥ 16)
    {
      DISPLAY("Enjoy the ride - front row unlocked")
    }
    ELSE
    {
      DISPLAY("Enjoy the ride - back rows only")
    }
  }
  ELSE
  {
    DISPLAY("Ride with an adult")
  }
}
ELSE
{
  DISPLAY("Too short to ride")
}

reference.python:
height = 52
age = 14
if height >= 48:
    if age >= 12:
        if age >= 16:
            print("Enjoy the ride - front row unlocked")
        else:
            print("Enjoy the ride - back rows only")
    else:
        print("Ride with an adult")
else:
    print("Too short to ride")

reference.javascript:
let height = 52;
let age = 14;
if (height >= 48) {
  if (age >= 12) {
    if (age >= 16) {
      console.log("Enjoy the ride - front row unlocked");
    } else {
      console.log("Enjoy the ride - back rows only");
    }
  } else {
    console.log("Ride with an adult");
  }
} else {
  console.log("Too short to ride");
}

